L6750: "content": "import { Application, Graphics, Container } from 'pixi.js';
import { Pane } from 'tweakpane';
import { GridRenderer } from './grid-renderer';
import { GridType } from './types';
import { createDrawStateBlade, DrawStateBladeApi } from './draw-state-blade';
import palettesData from './assets/palettes.json';
import { ParticleSystem } from './particle-system';
import { Grid, SquareGrid, HexagonGrid, TriangleGrid } from './grid'; // Import new Grid classes

type ColorValue = string | { r: number; g: number; b: number; a?: number };

interface PaletteData {
  name: string;
  colors: Record<string, string>;
}

type LeftClickMode = 'draw' | 'spawnParticle';
type EdgeSelectionRule = 'randomNoBacktrack' | 'randomWithBacktrack' | 'clockwise' | 'counterClockwise' | 'followCursor' | 'avoidCursor';

interface AppConfig {
  gridWidth: number;
  gridHeight: number;
  gridType: GridType;
  gridScale: number;
  numStates: number;
  drawState: number;
  palette: Record<number, ColorValue>;
  selectedPalette: string;
  edgePalette: Record<number, ColorValue>;
  selectedEdgePalette: string;
  edgeColor: ColorValue;
  edgeWidth: number;
  edgeHighlightColor: ColorValue;
  visualizeEdgeDelta: boolean;
  showCoordinates: boolean;
  particleSpeed: number;
  leftClickMode: LeftClickMode;
  edgeSelectionRule: EdgeSelectionRule;
}

class GridApp {
  private app!: Application;
  private gridRenderer!: GridRenderer;
  private pane!: Pane;
  private config: AppConfig;
  private gridContainer!: Container;
  private edgeContainer!: Container;
  private particleContainer!: Container;
  private highlightedEdge: Graphics | null = null;
  private highlightedCell: Graphics | null = null;
  private highlightedVertex: Graphics | null = null;
  private cellStates: number[][] = [];
  private drawStateBlade: DrawStateBladeApi | null = null;
  private palettes: PaletteData[] = [];
  private particleSystem!: ParticleSystem;
  private mouseX: number = 0;
  private mouseY: number = 0;
  private grid: Grid; // Instance of the abstract Grid

  constructor() {
    this.palettes = palettesData.palettes;

    const defaultPalette = this.palettes[0];
    const initialPalette: Record<number, ColorValue> = {};
    Object.keys(defaultPalette.colors).forEach(key => {
      initialPalette[parseInt(key)] = defaultPalette.colors[key];
    });

    const initialEdgePalette: Record<number, ColorValue> = {};
    Object.keys(defaultPalette.colors).forEach(key => {
      initialEdgePalette[parseInt(key)] = defaultPalette.colors[key];
    });

    this.config = {
      gridWidth: 25,
      gridHeight: 18,
      gridType: 'hexagons',
      gridScale: 30,
      numStates: 8,
      drawState: 7,
      palette: initialPalette,
      selectedPalette: defaultPalette.name,
      edgePalette: initialEdgePalette,
      selectedEdgePalette: defaultPalette.name,
      edgeColor: '#ffffff',
      edgeWidth: 1,
      edgeHighlightColor: '#ffff00',
      visualizeEdgeDelta: false,
      showCoordinates: false,
      particleSpeed: 100,
      leftClickMode: 'randomNoBacktrack', // Default value
      edgeSelectionRule: 'spawnParticle', // Default value
    };

    this.grid = this.createGrid(this.config.gridType, this.config.gridScale); // Initialize grid here

    this.initPixi().then(() => {
      this.initInfoPanel();
      this.initTweakpane();
      this.initGrid();
      this.setupInteraction();
    });
  }

  private createGrid(gridType: GridType, scale: number): Grid {
    switch (gridType) {
      case 'squares': return new SquareGrid(scale);
      case 'hexagons': return new HexagonGrid(scale);
      case 'triangles': return new TriangleGrid(scale);
    }
  }

  private initInfoPanel() {
    const panel = document.createElement('div');
    panel.id = 'info-panel';

    const header = document.createElement('div');
    header.id = 'info-panel-header';

    const title = document.createElement('h2');
    title.textContent = 'About';

    const closeButton = document.createElement('button');
    closeButton.id = 'info-panel-close';
    closeButton.innerHTML = '×';
    closeButton.setAttribute('aria-label', 'Minimize info panel');
    closeButton.onclick = () => {
      panel.classList.add('minimized');
    };

    const reopenButton = document.createElement('button');
    reopenButton.id = 'info-panel-reopen';
    reopenButton.innerHTML = '&nbsp;ℹ';
    reopenButton.setAttribute('aria-label', 'Open info panel');
    reopenButton.onclick = () => {
      panel.classList.remove('minimized');
    };

    header.appendChild(title);
    header.appendChild(closeButton);
    header.appendChild(reopenButton);

    const content = document.createElement('div');
    content.id = 'info-panel-content';

    const description = document.createElement('p');
    description.textContent = `Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id est laborum. Sed ut perspiciatis unde omnis iste natus error sit voluptatem accusantium doloremque laudantium, totam rem aperiam, eaque ipsa quae ab illo inventore veritatis et quasi architecto beatae vitae dicta sunt explicabo. Nemo enim ipsam voluptatem quia voluptas sit aspernatur aut odit aut fugit, sed quia consequuntur magni dolores eos qui ratione voluptatem sequi nesciunt. Neque porro quisquam est, qui dolorem ipsum quia dolor sit amet, consectetur, adipisci velit, sed quia non numquam eius modi tempora incidunt ut labore et dolore magnam aliquam quaerat voluptatem.`;

    content.appendChild(description);

    const links = document.createElement('div');
    links.id = 'info-panel-links';

    const manualLink = document.createElement('a');
    manualLink.href = '#';
    manualLink.textContent = '📖 User Manual';
    manualLink.onclick = (e) => {
      e.preventDefault();
      alert('Manual coming soon!');
    };

    const githubLink = document.createElement('a');
    githubLink.href = 'https://github.com/example/cursor-hex';
    githubLink.textContent = '🔗 GitHub Repository';
    githubLink.target = '_blank';
    githubLink.rel = 'noopener noreferrer';

    const statisticsLink = document.createElement('a');
    statisticsLink.href = 'statistics.html';
    statisticsLink.textContent = '📊 Project Statistics';

    links.appendChild(manualLink);
    links.appendChild(githubLink);
    links.appendChild(statisticsLink);

    panel.appendChild(header);
    panel.appendChild(content);
    panel.appendChild(links);

    document.body.appendChild(panel);
  }

  private applyPalette(paletteName: string) {
    const palette = this.palettes.find(p => p.name === paletteName);
    if (!palette) return;

    Object.keys(palette.colors).forEach(key => {
      this.config.palette[parseInt(key)] = palette.colors[key];
    });

    this.updateDrawStateBlade();
    this.updateGrid();
  }

  private applyEdgePalette(paletteName: string) {
    const palette = this.palettes.find(p => p.name === paletteName);
    if (!palette) return;

    Object.keys(palette.colors).forEach(key => {
      this.config.edgePalette[parseInt(key)] = palette.colors[key];
    });

    this.updateGrid();
  }

  private async initPixi() {
    this.app = new Application();
    await this.app.init({ 
      antialias: true, 
      resizeTo: window,
      backgroundColor: 0x1a1a1a,
    });

    const appElement = document.getElementById('app');
    if (appElement) {
      appElement.appendChild(this.app.canvas);
    }

    this.gridContainer = new Container();
    this.edgeContainer = new Container();
    this.particleContainer = new Container();
    this.app.stage.addChild(this.gridContainer);
    this.app.stage.addChild(this.edgeContainer);
    this.app.stage.addChild(this.particleContainer);

    this.particleSystem = new ParticleSystem(this.particleContainer);

    this.app.ticker.add((ticker) => {
      this.particleSystem.update(
        ticker.deltaMS,
        this.config.particleSpeed,
        this.config.gridScale,
        this.gridRenderer,
        this.config.gridWidth,
        this.config.gridHeight,
        this.config.gridType,
        this.config.edgeSelectionRule,
        this.mouseX,
        this.mouseY
      );
    });
  }

  private initTweakpane() {
    this.pane = new Pane({ title: 'Grid Controls' });

    this.pane.addBinding(this.config, 'gridWidth', {
      min: 1, max: 80, step: 1, label: 'Grid Width',
    }).on('change', () => this.updateGrid());

    this.pane.addBinding(this.config, 'gridHeight', {
      min: 1, max: 50, step: 1, label: 'Grid Height',
    }).on('change', () => this.updateGrid());

    this.pane.addBinding(this.config, 'gridType', {
      options: { squares: 'squares', hexagons: 'hexagons', triangles: 'triangles' },
      label: 'Grid Type',
    }).on('change', () => this.updateGrid());

    this.pane.addBinding(this.config, 'gridScale', {
      min: 5, max: 100, step: 1, label: 'Grid Scale',
    }).on('change', () => this.updateGrid());

    this.pane.addBinding(this.config, 'numStates', {
      min: 2, max: 8, step: 1, label: 'Number of States',
    }).on('change', () => {
      if (this.config.drawState >= this.config.numStates) {
        this.config.drawState = this.config.numStates - 1;
      }
      this.updateDrawStateBlade();
      this.updateGrid();
    });

    const paletteOptions: Record<string, string> = {};
    this.palettes.forEach(palette => {
      paletteOptions[palette.name] = palette.name;
    });

    this.pane.addBinding(this.config, 'selectedPalette', {
      options: paletteOptions, label: 'Palette',
    }).on('change', () => this.applyPalette(this.config.selectedPalette));

    const edgePaletteOptions: Record<string, string> = {};
    this.palettes.forEach(palette => {
      edgePaletteOptions[palette.name] = palette.name;
    });

    this.pane.addBinding(this.config, 'selectedEdgePalette', {
      options: edgePaletteOptions, label: 'Edge Palette',
    }).on('change', () => this.applyEdgePalette(this.config.selectedEdgePalette));

    this.pane.addBinding(this.config, 'edgeColor', {
      label: 'Edge Color'
    }).on('change', () => this.updateGrid());

    this.pane.addBinding(this.config, 'edgeWidth', {
      label: 'Edge Width', min: 0, max: 10, step: 0.1,
    }).on('change', () => this.updateGrid());

    this.pane.addBinding(this.config, 'visualizeEdgeDelta', {
      label: 'Visualize Edge Delta'
    }).on('change', () => this.updateGrid());

    this.updateDrawStateBlade();

    this.pane.addBinding(this.config, 'showCoordinates', {
      label: 'Show Coordinates',
    }).on('change', () => this.updateGrid());

    this.pane.addBinding(this.config, 'leftClickMode', {
      options: { 'Draw Cell': 'draw', 'Spawn Particle': 'spawnParticle' },
      label: 'Left Click Mode',
    });

    this.pane.addBinding(this.config, 'particleSpeed', {
      min: 1, max: 400, step: 1, label: 'Particle Speed',
    });

    this.pane.addBinding(this.config, 'edgeSelectionRule', {
      options: {
        'Random (No Backtrack)': 'randomNoBacktrack',
        'Random (With Backtrack)': 'randomWithBacktrack',
        'Always Turn Clockwise': 'clockwise',
        'Always Turn Counter-Clockwise': 'counterClockwise',
        'Follow Cursor': 'followCursor',
        'Avoid Cursor': 'avoidCursor',
      },
      label: 'Edge Selection Rule',
    });

    this.pane.addButton({ title: 'Save to PNG', label: 'Save to PNG' }).on('click', () => this.saveToPNG());
    this.pane.addButton({ title: 'Load from PNG', label: 'Load from PNG' }).on('click', () => this.loadFromPNG());
  }

  private saveToPNG() {
    const canvas = document.createElement('canvas');
    canvas.width = this.config.gridWidth;
    canvas.height = this.config.gridHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const imageData = ctx.createImageData(canvas.width, canvas.height);
    const data = imageData.data;

    for (let row = 0; row < this.config.gridHeight; row++) {
      for (let col = 0; col < this.config.gridWidth; col++) {
