import { Pane } from 'tweakpane';
import { GridRenderer } from './grid-renderer';
import { GridType } from './types';
import { createDrawStateBlade, DrawStateBladeApi } from './draw-state-blade';
import palettesData from './assets/palettes.json';
import { ParticleSystem } from './particle-system';
import { Grid, SquareGrid, HexagonGrid, TriangleGrid } from './grid'; // Import new Grid classes

type ColorValue = string | { r: number; g: number; b: number; a?: number };

interface PaletteData {
  name: string;
  colors: Record<string, string>;
}

type LeftClickMode = 'draw' | 'spawnParticle';
type EdgeSelectionRule = 'randomNoBacktrack' | 'randomWithBacktrack' | 'clockwise' | 'counterClockwise' | 'followCursor' | 'avoidCursor';

interface AppConfig {
  gridWidth: number;
  gridHeight: number;
  gridType: GridType;
  gridScale: number;
  numStates: number;
  drawState: number;
  palette: Record<number, ColorValue>;
  selectedPalette: string;
  edgePalette: Record<number, ColorValue>;
  selectedEdgePalette: string;
  edgeColor: ColorValue;
  edgeWidth: number;
  edgeHighlightColor: ColorValue;
  visualizeEdgeDelta: boolean;
  showCoordinates: boolean;
  particleSpeed: number;
  leftClickMode: LeftClickMode;
  edgeSelectionRule: EdgeSelectionRule;
}

class GridApp {
  private app!: Application;
  private gridRenderer!: GridRenderer;
  private pane!: Pane;
  private config: AppConfig;
  private gridContainer!: Container;
  private edgeContainer!: Container;
  private particleContainer!: Container;
  private highlightedEdge: Graphics | null = null;
  private highlightedCell: Graphics | null = null;
  private highlightedVertex: Graphics | null = null;
  private cellStates: number[][] = [];
  private drawStateBlade: DrawStateBladeApi | null = null;
  private palettes: PaletteData[] = [];
  private particleSystem!: ParticleSystem;
  private mouseX: number = 0;
  private mouseY: number = 0;
  private grid: Grid; // Instance of the abstract Grid

  constructor() {
    this.palettes = palettesData.palettes;

    const defaultPalette = this.palettes[0];
    const initialPalette: Record<number, ColorValue> = {};
    Object.keys(defaultPalette.colors).forEach(key => {
      initialPalette[parseInt(key)] = defaultPalette.colors[key];
    });

    const initialEdgePalette: Record<number, ColorValue> = {};
    Object.keys(defaultPalette.colors).forEach(key => {
      initialEdgePalette[parseInt(key)] = defaultPalette.colors[key];
    });

    this.config = {
      gridWidth: 25,
      gridHeight: 18,
      gridType: 'hexagons',
      gridScale: 30,
      numStates: 8,
      drawState: 7,
      palette: initialPalette,
      selectedPalette: defaultPalette.name,
      edgePalette: initialEdgePalette,
      selectedEdgePalette: defaultPalette.name,
      edgeColor: '#ffffff',
      edgeWidth: 1,
      edgeHighlightColor: '#ffff00',
      visualizeEdgeDelta: false,
      showCoordinates: false,
      particleSpeed: 100,
      leftClickMode: 'randomNoBacktrack', // Default value
      edgeSelectionRule: 'spawnParticle', // Default value
    };

    this.grid = this.createGrid(this.config.gridType, this.config.gridScale); // Initialize grid here

    this.initPixi().then(() => {
      this.initInfoPanel();
      this.initTweakpane();
      this.initGrid();
      this.setupInteraction();
    });
  }

  private createGrid(gridType: GridType, scale: number): Grid {
    switch (gridType) {
      case 'squares': return new SquareGrid(scale);
      case 'hexagons': return new HexagonGrid(scale);
      case 'triangles': return new TriangleGrid(scale);
    }
  }

  private initInfoPanel() {
    const panel = document.createElement('div');
    panel.id = 'info-panel';

    const header = document.createElement('div');
    header.id = 'info-panel-header';

    const title = document.createElement('h2');
