import { describe, it, expect } from 'vitest';
import { TriangleGrid } from './grid';

describe('TriangleGrid Bug Reproduction', () => {
  const scale = 100;
  const grid = new TriangleGrid(scale);
  const triHeight = scale * Math.sqrt(3) / 2;

  // Triangle (0,0) is Upward.
  // Center roughly at (50, 43.3)
  // Vertices: (50, 0), (0, 86.6), (100, 86.6)

  // Left edge goes from (50, 0) to (0, 86.6)
  // Equation: y = -1.732 * (x - 50) => y = -1.732x + 86.6
  // Check point (10, 10).
  // At x=10, y on edge is -17.32 + 86.6 = 69.28.
  // Point (10, 10) is well below the edge? No, y increases downwards.
  // Wait, coordinate system: y=0 is top.
  // Vertices again:
  // (50, 0) is top tip.
  // (0, 86.6) is bottom left.
  // (100, 86.6) is bottom right.
  // Point (10, 10).
  // Edge from (50,0) to (0, 86.6).
  // At y=10. x on edge?
  // x goes from 50 to 0 as y goes 0 to 86.6.
  // x = 50 - (y / 86.6) * 50 = 50 - (10/86.6)*50 = 50 - 5.77 = 44.2.
  // So at y=10, the triangle starts at x=44.2.
  // Point (10, 10) is at x=10.
  // So (10, 10) is to the LEFT of the triangle (0,0).

  // It should belong to the neighbor to the left/top.
  // Neighbor to Left of (0,0) is (-1, 0) (Downward).
  // Triangle (-1, 0) vertices:
  // CenterX = -0.5*100 + 50 = 0.
  // CenterY = 43.3.
  // Vertices: (-50, 0), (50, 0), (0, 86.6).
  // Point (10, 10) is inside this triangle?
  // y=10. x range?
  // Left edge (-50,0) to (0, 86.6). Right edge (50, 0) to (0, 86.6).
  // Right edge x at y=10: x goes 50 to 0.
  // x = 50 - (10/86.6)*50 = 44.2.
  // So x must be < 44.2.
  // Left edge x at y=10: x goes -50 to 0.
  // x = -50 + ... = -44.2.
  // So x range is [-44.2, 44.2].
  // x=10 is inside Triangle (-1, 0).

  // Current implementation:
  // row = floor(10 / 86.6) = 0.
  // col = floor(10 / 50) = 0.
  // Returns (0,0).
  // BUT it should be (-1, 0).

  it('should correctly identify cell for point (10, 10) as (-1, 0), not (0, 0)', () => {
    const point = { x: 10, y: 10 };
    const cell = grid.pixelToCell(point);

    console.log(`Point (${point.x}, ${point.y}) mapped to cell:`, cell);

    // This expectation is what we WANT (correct behavior)
    // It is expected to FAIL with the current implementation
    expect(cell).toEqual({ col: -1, row: 0 });
  });

  it('should correctly identify cell for point (50, 10) as (0, 0)', () => {
    // (50, 10) is inside Triangle (0,0) (top tip is 50,0)
    // x range at y=10 is [44.2, 55.8] approx.
    // So 50 is inside.
    const point = { x: 50, y: 10 };
    const cell = grid.pixelToCell(point);
    expect(cell).toEqual({ col: 0, row: 0 });
  });
});

