pixelToCell(pixel: Point): { col: number; row: number; } {
  const q = pixel.x / (this.triWidth / 2);
  const r = pixel.y / this.triHeight;
  let col = Math.floor(q);
  const row = Math.floor(r);

  const u = q - col;
  const v = r - row;

  if ((row + col) % 2 === 0) {
    if (u + v < 1) {
      col--;
    }
  } else {
    if (u < v) {
      col--;
    }
  }

  return { col, row };
}

